export declare const WEBVIEW_POST_HEIGHT_SCRIPT = "\n(function () {\n  var ROOT_ID = 'survey-html-root';\n  function measureAndPost() {\n    var root = document.getElementById(ROOT_ID);\n    var b = document.body;\n    var e = document.documentElement;\n    var fromRoot = 0;\n    if (root) {\n      fromRoot = Math.max(\n        root.scrollHeight,\n        root.offsetHeight,\n        root.getBoundingClientRect ? root.getBoundingClientRect().height : 0\n      );\n    }\n    var h = Math.max(\n      fromRoot,\n      b ? b.scrollHeight : 0,\n      e ? e.scrollHeight : 0,\n      b ? b.offsetHeight : 0,\n      e ? e.offsetHeight : 0,\n      b ? b.clientHeight : 0,\n      e ? e.clientHeight : 0\n    );\n    window.ReactNativeWebView.postMessage(String(h));\n  }\n  measureAndPost();\n  setTimeout(measureAndPost, 50);\n  setTimeout(measureAndPost, 200);\n  setTimeout(measureAndPost, 500);\n  setTimeout(measureAndPost, 1200);\n})();\ntrue;\n";
